//SOUND_BEGIN
// =========================================================================
// Title: Dust Storm Sonification (Pure Wind/Sand) =========================================================================

// --- Le funzioni matematiche originali ---
float tri(in float x) { 
    return abs(fract(x) - 0.5); 
}

vec3 tri3(in vec3 p) { 
    return vec3(tri(p.z + tri(p.y * 1.0)), tri(p.z + tri(p.x * 1.0)), tri(p.y + tri(p.x * 1.0))); 
}

// Generatore di turbolenza frattale 3D (il vento)
float triNoise3d(in vec3 p, in float spd, in float time) {
    float z = 1.4;
    float rz = 0.0;
    vec3 bp = p;
    for (float i = 0.0; i <= 3.0; i++) {
        vec3 dg = tri3(bp * 2.0);
        p += (dg + time * spd);
        bp *= 1.8;
        z *= 1.5;
        p *= 1.2;
        rz += (tri(p.z + tri(p.x + tri(p.y)))) / z;
        bp += 0.14;
    }
    return rz;
}

// --- Generazione Audio ---
vec2 mainSound(int samp, float time) {
    // 1. Muoviamo i "microfoni virtuali" attraverso il rumore 3D
    vec3 pL = vec3(time * 150.0, time * 50.0, 0.0);
    vec3 pR = vec3(time * 140.0, time * 60.0, 10.0);

    // 2. Estraiamo il rumore della tempesta
    float noiseL = triNoise3d(pL, 0.0, time);
    float noiseR = triNoise3d(pR, 0.0, time);

    // 3. Centriamo l'onda (il triNoise restituisce solo valori positivi) 
    // e ne regoliamo l'ampiezza per dare dinamica alla sabbia
    noiseL = (noiseL - 0.4) * 2.5;
    noiseR = (noiseR - 0.4) * 2.5;

    // 4. Mix finale: Solo il fruscio del vento e della sabbia, leggermente abbassato (80%)
    vec2 audio = vec2(noiseL, noiseR) * 0.8;

    // 5. Inviluppo per entrare dolcemente
    float env = smoothstep(0.0, 2.0, time);

    return clamp(audio * env, -1.0, 1.0);
}
//SOUND_END
